mapper.select:
SELECT ips.id ,ips.security_code ,ips.security_short_name ,ips.adjuster_name ,ips.entry_time ,ips.target_pool_id ,p.pool_name AS target_pool_name FROM ip_pool_status ips JOIN dict_security_type dst ON ips.security_type = dst.security_type LEFT JOIN ip_investment_pool p ON ips.target_pool_id = p.id
ips.is_deleted = 0 AND ips.audit_status = '20' AND dst.category_type = 'company'
AND ips.target_pool_id IN
#{pid}
AND ips.security_code LIKE CONCAT('%', #{subjectCode}, '%')
AND ips.entry_time >= #{entryTimeStart}
AND ips.entry_time <= #{entryTimeEnd}
AND ips.adjuster_name LIKE CONCAT('%', #{adjusterName}, '%')
ORDER BY ips.entry_time DESC ,ips.id DESC
